                  for (index := 4;  index < arraysize(patternTokenized); index := index + 1){

                        // ADF - 20/02/2024  Elimination de l'extension encore présente dans le nom du fichier 
                        contribFilenameArrayTmp := strtokenize( contribFilenameArray[index] ,  "[\.]{1}");  
