                                 expectedFileName := expectedFileName + "_" + contribFilenameArray[index];   // ADF - 13/02/2024 NEW [index + 1] ==> [index]
                            }
                        }
                  }
                  expectedFileName := expectedFileName + expectedFileNamePart ;   // ADF - 20/02/2024 nom final en majuscule

                }  else {
                    foreach  patternToken in patternTokenized do {
                        if (strstart(patternToken, "${")) {
                            notInPattern:=3;
