                                    expectedFileNamePart := strcat(".",  expectedFileNamePart);
                                } else {
                                    expectedFileNamePart := strcat("_",  expectedFileNamePart);
                                }
                            }
                        } else {
                            first := 0;
                        }
                        expectedFileName := strcat(expectedFileName, expectedFileNamePart);
                    }    
